#include<bits/stdc++.h>
using namespace std;
bool v[100066];
vector<int> e[100066];
struct node{
    int x,y;
};
int n;
node dfs(int x, int f) {

    node ans;
    ans.x=f;
    ans.y=x;
	v[x] = 1;
	for (int i = 0; i < e[x].size(); i++) {
		if (!v[e[x][i]]) {
            node temp=dfs(e[x][i],f+1);
			if(temp.x>ans.x){
                ans.x=temp.x;
                ans.y=temp.y;
            }
		}
	}
	v[x] = 0;
	return ans;

}
int dfs2(int x, int f) {
	int ans = f;
	v[x] = 1;
	for (int i = 0; i < e[x].size(); i++) {
		if (!v[e[x][i]]) {
			ans = max(ans, dfs2(e[x][i], f + 1));
		}
	}
	v[x] = 0;
	return ans;
}
int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		int x, y;
		cin >> x >> y;
		e[x].push_back(y);
		e[y].push_back(x);
	}
    node ans=dfs(1,0);
	cout<<dfs2(ans.y,0);
	return 0;
}
